class Solution:
    def countAlternatingSubarrays(self, nums):
        total = 0
        run = 1
        for i in range(1, len(nums)):
            if nums[i] != nums[i - 1]:
                run += 1
            else:
                total += run * (run + 1) // 2
                run = 1
        total += run * (run + 1) // 2
        return total

