class Solution:
    def countAlternatingSubarrays(self, nums):
        total = 0
        run = 0
        for i in range(len(nums)):
            if i > 0 and nums[i] != nums[i - 1]:
                run += 1
            else:
                run = 1
            total += run
        return total

